      cm.Parameters.Add(new TParameter("id", OleDbType.Numeric, 0, ParameterDirection.InputOutput, true, 24, 10, "ID", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(-99992.93)));
      cm.Parameters.Add(new TParameter("id_contabanco_saldo", OleDbType.Numeric, 0, ParameterDirection.InputOutput, true, 24, 10, "ID_CONTABANCO_SALDO", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(-99992.93)));
      cm.Parameters.Add(new TParameter("id_finalidade", OleDbType.Numeric, 0, ParameterDirection.InputOutput, true, 24, 10, "ID_FINALIDADE", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(-99992.93)));
      cm.Parameters.Add(new TParameter("saldo", OleDbType.Numeric, 0, ParameterDirection.InputOutput, true, 20, 10, "SALDO", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(-99992.93)));

      switch(operation) {
      case CommandOperation.Insert: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Insert")); break;
      case CommandOperation.Update: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Update")); break;
