          if(lower == "id_contabanco") { result.Add(toLower ? "id_contabanco" : column); continue; }
          if(lower == "numero") { result.Add(toLower ? "numero" : column); continue; }
          if(lower == "valor") { result.Add(toLower ? "valor" : column); continue; }
          if(lower == "data_emissao") { result.Add(toLower ? "data_emissao" : column); continue; }
          if(lower == "data_apresentacao") { result.Add(toLower ? "data_apresentacao" : column); continue; }
          if(lower == "id_compra") { result.Add(toLower ? "id_compra" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id", "id_contabanco", "numero", "valor", "data_emissao", "data_apresentacao", 
                                           "id_compra" }
                          : new string[] { "ID", "ID_CONTABANCO", "NUMERO", "VALOR", "DATA_EMISSAO", "DATA_APRESENTACAO", 
                                           "ID_COMPRA" });
        else
          result.AddRange(toLower
                          ? new string[] { "id", "id_contabanco", "numero", "valor", "data_emissao", "data_apresentacao", 
                                           "id_compra" }
                          : new string[] { "ID", "ID_CONTABANCO", "NUMERO", "VALOR", "DATA_EMISSAO", "DATA_APRESENTACAO", 
                                           "ID_COMPRA" });

      return result;
    }


