    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id") { result.Add(toLower ? "id" : column); continue; }
          if(lower == "banco") { result.Add(toLower ? "banco" : column); continue; }
          if(lower == "agencia") { result.Add(toLower ? "agencia" : column); continue; }
          if(lower == "conta") { result.Add(toLower ? "conta" : column); continue; }
          if(lower == "titular") { result.Add(toLower ? "titular" : column); continue; }
          if(lower == "cnpj") { result.Add(toLower ? "cnpj" : column); continue; }
          if(lower == "id_prestador") { result.Add(toLower ? "id_prestador" : column); continue; }
          if(lower == "ativa") { result.Add(toLower ? "ativa" : column); continue; }
          if(lower == "id_fonterecurso") { result.Add(toLower ? "id_fonterecurso" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id", "banco", "agencia", "conta", "titular", "cnpj", "id_prestador", 
                                           "ativa", "id_fonterecurso" }
                          : new string[] { "ID", "BANCO", "AGENCIA", "CONTA", "TITULAR", "CNPJ", "ID_PRESTADOR", 
                                           "ATIVA", "ID_FONTERECURSO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id", "banco", "agencia", "conta", "titular", "cnpj", "id_prestador", 
                                           "ativa", "id_fonterecurso" }
                          : new string[] { "ID", "BANCO", "AGENCIA", "CONTA", "TITULAR", "CNPJ", "ID_PRESTADOR", 
                                           "ATIVA", "ID_FONTERECURSO" });

      return result;
    }


