    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_pc_contabanco.id"
      });
      if(scColumns.Contains("banco")) list.Add("ly_pc_contabanco.banco");
      if(scColumns.Contains("agencia")) list.Add("ly_pc_contabanco.agencia");
      if(scColumns.Contains("conta")) list.Add("ly_pc_contabanco.conta");
      if(scColumns.Contains("titular")) list.Add("ly_pc_contabanco.titular");
      if(scColumns.Contains("cnpj")) list.Add("ly_pc_contabanco.cnpj");
      if(scColumns.Contains("id_prestador")) list.Add("ly_pc_contabanco.id_prestador");
      if(scColumns.Contains("ativa")) list.Add("ly_pc_contabanco.ativa");
      if(scColumns.Contains("id_fonterecurso")) list.Add("ly_pc_contabanco.id_fonterecurso");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_pc_contabanco " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_pc_contabanco");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_pc_contabanco");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["BANCO"] != null && string.IsNullOrEmpty(dr["BANCO"].ToString()))
              dr["BANCO"] = DBNull.Value;
            if (dr["AGENCIA"] != null && string.IsNullOrEmpty(dr["AGENCIA"].ToString()))
              dr["AGENCIA"] = DBNull.Value;
            if (dr["CONTA"] != null && string.IsNullOrEmpty(dr["CONTA"].ToString()))
              dr["CONTA"] = DBNull.Value;
            if (dr["TITULAR"] != null && string.IsNullOrEmpty(dr["TITULAR"].ToString()))
              dr["TITULAR"] = DBNull.Value;
            if (dr["CNPJ"] != null && string.IsNullOrEmpty(dr["CNPJ"].ToString()))
              dr["CNPJ"] = DBNull.Value;
            if (dr["ID_PRESTADOR"] != null && string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
              dr["ID_PRESTADOR"] = DBNull.Value;
            if (dr["ATIVA"] != null && string.IsNullOrEmpty(dr["ATIVA"].ToString()))
              dr["ATIVA"] = DBNull.Value;
            if (dr["ID_FONTERECURSO"] != null && string.IsNullOrEmpty(dr["ID_FONTERECURSO"].ToString()))
              dr["ID_FONTERECURSO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["BANCO"] == null || string.IsNullOrEmpty(dr["BANCO"].ToString()))
            {
              return "Favor informar o banco.";
            }

            if (dr["BANCO"] != null && !string.IsNullOrEmpty(dr["BANCO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["BANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["BANCO"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["BANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["BANCO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O banco deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["AGENCIA"] == null || string.IsNullOrEmpty(dr["AGENCIA"].ToString()))
            {
              return "Favor informar a agęncia.";
            }

            if (dr["AGENCIA"] != null && !string.IsNullOrEmpty(dr["AGENCIA"].ToString()))
            {
              if (dr["AGENCIA"].ToString().Length > 7)
              {
                return "A agęncia deve possuir no máximo 7 caracteres.";
              }
            }

            if (dr["CONTA"] == null || string.IsNullOrEmpty(dr["CONTA"].ToString()))
            {
              return "Favor informar a conta.";
            }

            if (dr["CONTA"] != null && !string.IsNullOrEmpty(dr["CONTA"].ToString()))
            {
              if (dr["CONTA"].ToString().Length > 50)
              {
                return "A conta deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["TITULAR"] == null || string.IsNullOrEmpty(dr["TITULAR"].ToString()))
            {
              return "Favor informar o titular.";
            }

            if (dr["TITULAR"] != null && !string.IsNullOrEmpty(dr["TITULAR"].ToString()))
            {
              if (dr["TITULAR"].ToString().Length > 100)
              {
                return "O titular deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["CNPJ"] != null && !string.IsNullOrEmpty(dr["CNPJ"].ToString()))
            {
              if ((Convert.ToDecimal(dr["CNPJ"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CNPJ"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["CNPJ"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CNPJ"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O cnpj deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_PRESTADOR"] == null || string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
            {
              return "Favor informar o prestador de contas.";
            }

            if (dr["ID_PRESTADOR"] != null && !string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O prestador de contas deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ATIVA"] == null || string.IsNullOrEmpty(dr["ATIVA"].ToString()))
            {
              return "Favor informar o campo de conta ativa.";
            }

            if (dr["ATIVA"] != null && !string.IsNullOrEmpty(dr["ATIVA"].ToString()))
            {
              if (dr["ATIVA"].ToString().Length > 1)
              {
                return "O campo de conta ativa deve possuir no máximo 1 caractere.";
              }
            }

            if (dr["ID_FONTERECURSO"] == null || string.IsNullOrEmpty(dr["ID_FONTERECURSO"].ToString()))
            {
              return "Favor informar a origem de recursos.";
            }

            if (dr["ID_FONTERECURSO"] != null && !string.IsNullOrEmpty(dr["ID_FONTERECURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_FONTERECURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FONTERECURSO"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_FONTERECURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FONTERECURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A origem de recursos deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }
      }
      return "";
    }

