    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["ID_CONTABANCO"] != null && string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
              dr["ID_CONTABANCO"] = DBNull.Value;
            if (dr["ID_PRESTCONTAS"] != null && string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
              dr["ID_PRESTCONTAS"] = DBNull.Value;
