              dr["ATUALIZAR_FORMULARIOS"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_CONTABANCO"] == null || string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
            {
              return "Favor informar a conta bancária.";
            }

            if (dr["ID_CONTABANCO"] != null && !string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A conta bancária deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_PRESTCONTAS"] == null || string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              return "Favor informar a Saldo.";
            }

            if (dr["ID_PRESTCONTAS"] != null && !string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A Saldo deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["SALDO_INICIAL"] != null && !string.IsNullOrEmpty(dr["SALDO_INICIAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["SALDO_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SALDO_INICIAL"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["SALDO_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SALDO_INICIAL"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O saldo inicial deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["SALDO_FINAL"] != null && !string.IsNullOrEmpty(dr["SALDO_FINAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["SALDO_FINAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SALDO_FINAL"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["SALDO_FINAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SALDO_FINAL"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O saldo final deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["ATUALIZAR_FORMULARIOS"] != null && !string.IsNullOrEmpty(dr["ATUALIZAR_FORMULARIOS"].ToString()))
            {
              if (dr["ATUALIZAR_FORMULARIOS"].ToString().Length > 1)
              {
                return "O atualizar formulário deve possuir no máximo 1 caractere.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

