    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_pc_despesa.id"
      });
      if(scColumns.Contains("data")) list.Add("ly_pc_despesa.data");
      if(scColumns.Contains("num_comprov")) list.Add("ly_pc_despesa.num_comprov");
      if(scColumns.Contains("tipo_comprov")) list.Add("ly_pc_despesa.tipo_comprov");
      if(scColumns.Contains("desconto")) list.Add("ly_pc_despesa.desconto");
      if(scColumns.Contains("valor")) list.Add("ly_pc_despesa.valor");
      if(scColumns.Contains("id_finalidade")) list.Add("ly_pc_despesa.id_finalidade");
      if(scColumns.Contains("id_compra")) list.Add("ly_pc_despesa.id_compra");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_pc_despesa " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_pc_despesa");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_pc_despesa");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["NUM_COMPROV"] != null && string.IsNullOrEmpty(dr["NUM_COMPROV"].ToString()))
              dr["NUM_COMPROV"] = DBNull.Value;
            if (dr["TIPO_COMPROV"] != null && string.IsNullOrEmpty(dr["TIPO_COMPROV"].ToString()))
              dr["TIPO_COMPROV"] = DBNull.Value;
            if (dr["DESCONTO"] != null && string.IsNullOrEmpty(dr["DESCONTO"].ToString()))
              dr["DESCONTO"] = DBNull.Value;
            if (dr["VALOR"] != null && string.IsNullOrEmpty(dr["VALOR"].ToString()))
              dr["VALOR"] = DBNull.Value;
            if (dr["ID_FINALIDADE"] != null && string.IsNullOrEmpty(dr["ID_FINALIDADE"].ToString()))
              dr["ID_FINALIDADE"] = DBNull.Value;
            if (dr["ID_COMPRA"] != null && string.IsNullOrEmpty(dr["ID_COMPRA"].ToString()))
              dr["ID_COMPRA"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["DATA"] == null || string.IsNullOrEmpty(dr["DATA"].ToString()))
            {
              return "Favor informar a data.";
            }

            if (dr["DATA"] != null && dr["DATA"].ToString() != "")
            {
              dr["DATA"] = Convert.ToDateTime(dr["DATA"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["NUM_COMPROV"] != null && !string.IsNullOrEmpty(dr["NUM_COMPROV"].ToString()))
            {
              if (dr["NUM_COMPROV"].ToString().Length > 50)
              {
                return "O número do comprovante deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["TIPO_COMPROV"] != null && !string.IsNullOrEmpty(dr["TIPO_COMPROV"].ToString()))
            {
              if (dr["TIPO_COMPROV"].ToString().Length > 40)
              {
                return "O tipo de comprovante deve possuir no máximo 40 caracteres.";
              }
            }

            if (dr["DESCONTO"] != null && !string.IsNullOrEmpty(dr["DESCONTO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O desconto deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["VALOR"] == null || string.IsNullOrEmpty(dr["VALOR"].ToString()))
            {
              return "Favor informar o valor.";
            }

            if (dr["VALOR"] != null && !string.IsNullOrEmpty(dr["VALOR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O valor deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["ID_FINALIDADE"] != null && !string.IsNullOrEmpty(dr["ID_FINALIDADE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A finalidade deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_COMPRA"] == null || string.IsNullOrEmpty(dr["ID_COMPRA"].ToString()))
            {
              return "Favor informar a compra.";
            }

            if (dr["ID_COMPRA"] != null && !string.IsNullOrEmpty(dr["ID_COMPRA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_COMPRA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_COMPRA"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_COMPRA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_COMPRA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A compra deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

