          result.AddRange(toLower
                          ? new string[] { "id", "sigla", "nome", "flg_pnae", "codigo_formulario" }
                          : new string[] { "ID", "SIGLA", "NOME", "FLG_PNAE", "CODIGO_FORMULARIO" });
