    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_PRESTCONTAS"] == null || string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              return "Favor informar a prestaçăo de contas.";
            }

            if (dr["ID_PRESTCONTAS"] != null && !string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A prestaçăo de contas deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["C01_NOMEUE"] == null || string.IsNullOrEmpty(dr["C01_NOMEUE"].ToString()))
            {
              return "Favor informar o Nome da Unidade Escolar/Coordenadoria.";
            }

            if (dr["C01_NOMEUE"] != null && !string.IsNullOrEmpty(dr["C01_NOMEUE"].ToString()))
            {
              if (dr["C01_NOMEUE"].ToString().Length > 100)
              {
                return "O Nome da Unidade Escolar/Coordenadoria deve possuir no máximo 100 caracteres.";
              }
            }

