    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["ID_PRESTCONTAS"] != null && string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
              dr["ID_PRESTCONTAS"] = DBNull.Value;
            if (dr["INFO"] != null && string.IsNullOrEmpty(dr["INFO"].ToString()))
              dr["INFO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_PRESTCONTAS"] == null || string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              return "Favor informar a prestaçăo de contas.";
            }

            if (dr["ID_PRESTCONTAS"] != null && !string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A prestaçăo de contas deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["INFO"] != null && !string.IsNullOrEmpty(dr["INFO"].ToString()))
            {
              if (dr["INFO"].ToString().Length > 2000)
              {
                return "O Campo de Informaçőes deve possuir no máximo 2000 caracteres.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

