      if(scColumns.Contains("c16_flg")) list.Add("ly_pc_formulario2.c16_flg");
      if(scColumns.Contains("c16_folhas")) list.Add("ly_pc_formulario2.c16_folhas");
      if(scColumns.Contains("c17_flg")) list.Add("ly_pc_formulario2.c17_flg");
      if(scColumns.Contains("c17_folhas")) list.Add("ly_pc_formulario2.c17_folhas");
