    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id") { result.Add(toLower ? "id" : column); continue; }
          if(lower == "valor_unitario") { result.Add(toLower ? "valor_unitario" : column); continue; }
          if(lower == "quantidade") { result.Add(toLower ? "quantidade" : column); continue; }
          if(lower == "valor_total") { result.Add(toLower ? "valor_total" : column); continue; }
          if(lower == "inventario_ini") { result.Add(toLower ? "inventario_ini" : column); continue; }
          if(lower == "inventario_fim") { result.Add(toLower ? "inventario_fim" : column); continue; }
          if(lower == "id_despesa") { result.Add(toLower ? "id_despesa" : column); continue; }
          if(lower == "id_item") { result.Add(toLower ? "id_item" : column); continue; }
          if(lower == "marca") { result.Add(toLower ? "marca" : column); continue; }
          if(lower == "desconto") { result.Add(toLower ? "desconto" : column); continue; }
          if(lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
          if(lower == "id_finalidade") { result.Add(toLower ? "id_finalidade" : column); continue; }
          if(lower == "add_01") { result.Add(toLower ? "add_01" : column); continue; }
          if(lower == "add_02") { result.Add(toLower ? "add_02" : column); continue; }
          if(lower == "add_03") { result.Add(toLower ? "add_03" : column); continue; }
          if(lower == "add_04") { result.Add(toLower ? "add_04" : column); continue; }
          if(lower == "sub_01") { result.Add(toLower ? "sub_01" : column); continue; }
          if(lower == "sub_02") { result.Add(toLower ? "sub_02" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id", "valor_unitario", "quantidade", "valor_total", "inventario_ini", 
                                           "inventario_fim", "id_despesa", "id_item", "marca", "desconto", "descricao", "id_finalidade", 
                                           "add_01", "add_02", "add_03", "add_04", "sub_01", "sub_02" }
                          : new string[] { "ID", "VALOR_UNITARIO", "QUANTIDADE", "VALOR_TOTAL", "INVENTARIO_INI", 
                                           "INVENTARIO_FIM", "ID_DESPESA", "ID_ITEM", "MARCA", "DESCONTO", "DESCRICAO", "ID_FINALIDADE", 
                                           "ADD_01", "ADD_02", "ADD_03", "ADD_04", "SUB_01", "SUB_02" });
        else
          result.AddRange(toLower
                          ? new string[] { "id", "valor_unitario", "quantidade", "valor_total", "inventario_ini", 
                                           "inventario_fim", "id_despesa", "id_item", "marca", "desconto", "descricao", "id_finalidade", 
                                           "add_01", "add_02", "add_03", "add_04", "sub_01", "sub_02" }
                          : new string[] { "ID", "VALOR_UNITARIO", "QUANTIDADE", "VALOR_TOTAL", "INVENTARIO_INI", 
                                           "INVENTARIO_FIM", "ID_DESPESA", "ID_ITEM", "MARCA", "DESCONTO", "DESCRICAO", "ID_FINALIDADE", 
                                           "ADD_01", "ADD_02", "ADD_03", "ADD_04", "SUB_01", "SUB_02" });

      return result;
    }


