    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_pc_itemdespesa.id"
      });
      if(scColumns.Contains("valor_unitario")) list.Add("ly_pc_itemdespesa.valor_unitario");
      if(scColumns.Contains("quantidade")) list.Add("ly_pc_itemdespesa.quantidade");
      if(scColumns.Contains("valor_total")) list.Add("ly_pc_itemdespesa.valor_total");
      if(scColumns.Contains("inventario_ini")) list.Add("ly_pc_itemdespesa.inventario_ini");
      if(scColumns.Contains("inventario_fim")) list.Add("ly_pc_itemdespesa.inventario_fim");
      if(scColumns.Contains("id_despesa")) list.Add("ly_pc_itemdespesa.id_despesa");
      if(scColumns.Contains("id_item")) list.Add("ly_pc_itemdespesa.id_item");
      if(scColumns.Contains("marca")) list.Add("ly_pc_itemdespesa.marca");
      if(scColumns.Contains("desconto")) list.Add("ly_pc_itemdespesa.desconto");
      if(scColumns.Contains("descricao")) list.Add("ly_pc_itemdespesa.descricao");
      if(scColumns.Contains("id_finalidade")) list.Add("ly_pc_itemdespesa.id_finalidade");
      if(scColumns.Contains("add_01")) list.Add("ly_pc_itemdespesa.add_01");
      if(scColumns.Contains("add_02")) list.Add("ly_pc_itemdespesa.add_02");
      if(scColumns.Contains("add_03")) list.Add("ly_pc_itemdespesa.add_03");
      if(scColumns.Contains("add_04")) list.Add("ly_pc_itemdespesa.add_04");
      if(scColumns.Contains("sub_01")) list.Add("ly_pc_itemdespesa.sub_01");
      if(scColumns.Contains("sub_02")) list.Add("ly_pc_itemdespesa.sub_02");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_pc_itemdespesa " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_pc_itemdespesa");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_pc_itemdespesa");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

