    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["VALOR_UNITARIO"] == null || string.IsNullOrEmpty(dr["VALOR_UNITARIO"].ToString()))
            {
              return "Favor informar o valor unitário.";
            }

            if (dr["VALOR_UNITARIO"] != null && !string.IsNullOrEmpty(dr["VALOR_UNITARIO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR_UNITARIO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_UNITARIO"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["VALOR_UNITARIO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_UNITARIO"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O valor unitário deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["QUANTIDADE"] == null || string.IsNullOrEmpty(dr["QUANTIDADE"].ToString()))
            {
              return "Favor informar a quantidade.";
            }

            if (dr["QUANTIDADE"] != null && !string.IsNullOrEmpty(dr["QUANTIDADE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["QUANTIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QUANTIDADE"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["QUANTIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QUANTIDADE"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "A quantidade deve ser um valor numérico com, no máximo, 4 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["VALOR_TOTAL"] == null || string.IsNullOrEmpty(dr["VALOR_TOTAL"].ToString()))
            {
              return "Favor informar o total.";
            }

            if (dr["VALOR_TOTAL"] != null && !string.IsNullOrEmpty(dr["VALOR_TOTAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR_TOTAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_TOTAL"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["VALOR_TOTAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_TOTAL"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O total deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["INVENTARIO_INI"] != null && !string.IsNullOrEmpty(dr["INVENTARIO_INI"].ToString()))
            {
              if ((Convert.ToDecimal(dr["INVENTARIO_INI"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INVENTARIO_INI"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["INVENTARIO_INI"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INVENTARIO_INI"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O inventário inicial deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["INVENTARIO_FIM"] != null && !string.IsNullOrEmpty(dr["INVENTARIO_FIM"].ToString()))
            {
              if ((Convert.ToDecimal(dr["INVENTARIO_FIM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INVENTARIO_FIM"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["INVENTARIO_FIM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INVENTARIO_FIM"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O inventário final deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_DESPESA"] == null || string.IsNullOrEmpty(dr["ID_DESPESA"].ToString()))
            {
              return "Favor informar a despesa.";
            }

            if (dr["ID_DESPESA"] != null && !string.IsNullOrEmpty(dr["ID_DESPESA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_DESPESA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_DESPESA"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_DESPESA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_DESPESA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A despesa deve ser um valor inteiro com 14 dígitos no máximo.";
