          if(lower == "id_contabanco") { result.Add(toLower ? "id_contabanco" : column); continue; }
          if(lower == "id_tipomov") { result.Add(toLower ? "id_tipomov" : column); continue; }
          if(lower == "id_finalidade") { result.Add(toLower ? "id_finalidade" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id", "valor", "data", "id_prestcontas", "id_contabanco", "id_tipomov", 
                                           "id_finalidade" }
                          : new string[] { "ID", "VALOR", "DATA", "ID_PRESTCONTAS", "ID_CONTABANCO", "ID_TIPOMOV", 
                                           "ID_FINALIDADE" });
        else
          result.AddRange(toLower
                          ? new string[] { "id", "valor", "data", "id_prestcontas", "id_contabanco", "id_tipomov", 
                                           "id_finalidade" }
                          : new string[] { "ID", "VALOR", "DATA", "ID_PRESTCONTAS", "ID_CONTABANCO", "ID_TIPOMOV", 
                                           "ID_FINALIDADE" });

