              dr["VALOR"] = DBNull.Value;
            if (dr["ID_PRESTCONTAS"] != null && string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
              dr["ID_PRESTCONTAS"] = DBNull.Value;
            if (dr["ID_CONTABANCO"] != null && string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
              dr["ID_CONTABANCO"] = DBNull.Value;
            if (dr["ID_TIPOMOV"] != null && string.IsNullOrEmpty(dr["ID_TIPOMOV"].ToString()))
              dr["ID_TIPOMOV"] = DBNull.Value;
            if (dr["ID_FINALIDADE"] != null && string.IsNullOrEmpty(dr["ID_FINALIDADE"].ToString()))
              dr["ID_FINALIDADE"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["VALOR"] == null || string.IsNullOrEmpty(dr["VALOR"].ToString()))
            {
              return "Favor informar o valor.";
            }

            if (dr["VALOR"] != null && !string.IsNullOrEmpty(dr["VALOR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O valor deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["DATA"] == null || string.IsNullOrEmpty(dr["DATA"].ToString()))
            {
              return "Favor informar a data.";
            }

            if (dr["DATA"] != null && dr["DATA"].ToString() != "")
            {
              dr["DATA"] = Convert.ToDateTime(dr["DATA"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["ID_PRESTCONTAS"] == null || string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              return "Favor informar a prestaçăo de contas.";
            }

            if (dr["ID_PRESTCONTAS"] != null && !string.IsNullOrEmpty(dr["ID_PRESTCONTAS"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTCONTAS"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A prestaçăo de contas deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_CONTABANCO"] == null || string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
            {
              return "Favor informar a conta bancária.";
            }

            if (dr["ID_CONTABANCO"] != null && !string.IsNullOrEmpty(dr["ID_CONTABANCO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CONTABANCO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A conta bancária deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_TIPOMOV"] == null || string.IsNullOrEmpty(dr["ID_TIPOMOV"].ToString()))
            {
              return "Favor informar o tipo de movimentaçăo.";
            }

            if (dr["ID_TIPOMOV"] != null && !string.IsNullOrEmpty(dr["ID_TIPOMOV"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_TIPOMOV"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_TIPOMOV"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_TIPOMOV"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_TIPOMOV"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O tipo de movimentaçăo deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_FINALIDADE"] != null && !string.IsNullOrEmpty(dr["ID_FINALIDADE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_FINALIDADE"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A finalidade deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }
      }
      return "";
    }

