      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["ID"] != null && string.IsNullOrEmpty(dr["ID"].ToString()))
              dr["ID"] = DBNull.Value;
            if (dr["ID_ITEMDESPESA"] != null && string.IsNullOrEmpty(dr["ID_ITEMDESPESA"].ToString()))
              dr["ID_ITEMDESPESA"] = DBNull.Value;
            if (dr["NUMPATRIM"] != null && string.IsNullOrEmpty(dr["NUMPATRIM"].ToString()))
              dr["NUMPATRIM"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID"] == null || string.IsNullOrEmpty(dr["ID"].ToString()))
            {
              return "Favor informar o id.";
            }

            if (dr["ID"] != null && !string.IsNullOrEmpty(dr["ID"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O id deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_ITEMDESPESA"] == null || string.IsNullOrEmpty(dr["ID_ITEMDESPESA"].ToString()))
            {
              return "Favor informar o item de despesa.";
            }

            if (dr["ID_ITEMDESPESA"] != null && !string.IsNullOrEmpty(dr["ID_ITEMDESPESA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_ITEMDESPESA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_ITEMDESPESA"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_ITEMDESPESA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_ITEMDESPESA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O item de despesa deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["NUMPATRIM"] == null || string.IsNullOrEmpty(dr["NUMPATRIM"].ToString()))
            {
              return "Favor informar o número patrimonial.";
            }

            if (dr["NUMPATRIM"] != null && !string.IsNullOrEmpty(dr["NUMPATRIM"].ToString()))
            {
              if ((Convert.ToDecimal(dr["NUMPATRIM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUMPATRIM"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["NUMPATRIM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUMPATRIM"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O número patrimonial deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

