    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_pc_periodoref.id"
      });
      if(scColumns.Contains("descperiodoref")) list.Add("ly_pc_periodoref.descperiodoref");
      if(scColumns.Contains("datainiaplicacao")) list.Add("ly_pc_periodoref.datainiaplicacao");
      if(scColumns.Contains("datafimaplicacao")) list.Add("ly_pc_periodoref.datafimaplicacao");
      if(scColumns.Contains("anoly")) list.Add("ly_pc_periodoref.anoly");
      if(scColumns.Contains("periodoly")) list.Add("ly_pc_periodoref.periodoly");
      if(scColumns.Contains("datainiprest")) list.Add("ly_pc_periodoref.datainiprest");
      if(scColumns.Contains("datafimprest")) list.Add("ly_pc_periodoref.datafimprest");
      if(scColumns.Contains("valormax_peqdesp")) list.Add("ly_pc_periodoref.valormax_peqdesp");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_pc_periodoref " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_pc_periodoref");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_pc_periodoref");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["DESCPERIODOREF"] != null && string.IsNullOrEmpty(dr["DESCPERIODOREF"].ToString()))
              dr["DESCPERIODOREF"] = DBNull.Value;
            if (dr["ANOLY"] != null && string.IsNullOrEmpty(dr["ANOLY"].ToString()))
              dr["ANOLY"] = DBNull.Value;
            if (dr["PERIODOLY"] != null && string.IsNullOrEmpty(dr["PERIODOLY"].ToString()))
              dr["PERIODOLY"] = DBNull.Value;
            if (dr["VALORMAX_PEQDESP"] != null && string.IsNullOrEmpty(dr["VALORMAX_PEQDESP"].ToString()))
              dr["VALORMAX_PEQDESP"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["DESCPERIODOREF"] == null || string.IsNullOrEmpty(dr["DESCPERIODOREF"].ToString()))
            {
              return "Favor informar o nome.";
            }

            if (dr["DESCPERIODOREF"] != null && !string.IsNullOrEmpty(dr["DESCPERIODOREF"].ToString()))
            {
              if (dr["DESCPERIODOREF"].ToString().Length > 20)
              {
                return "O nome deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["DATAINIAPLICACAO"] == null || string.IsNullOrEmpty(dr["DATAINIAPLICACAO"].ToString()))
            {
              return "Favor informar o início de período de utilizaçăo dos recursos.";
            }

            if (dr["DATAINIAPLICACAO"] != null && dr["DATAINIAPLICACAO"].ToString() != "")
            {
              dr["DATAINIAPLICACAO"] = Convert.ToDateTime(dr["DATAINIAPLICACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["DATAFIMAPLICACAO"] == null || string.IsNullOrEmpty(dr["DATAFIMAPLICACAO"].ToString()))
            {
              return "Favor informar o término do período de utilizaçăo dos recursos.";
            }

            if (dr["DATAFIMAPLICACAO"] != null && dr["DATAFIMAPLICACAO"].ToString() != "")
            {
              dr["DATAFIMAPLICACAO"] = Convert.ToDateTime(dr["DATAFIMAPLICACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["ANOLY"] == null || string.IsNullOrEmpty(dr["ANOLY"].ToString()))
            {
              return "Favor informar o ano do período letivo.";
            }

            if (dr["ANOLY"] != null && !string.IsNullOrEmpty(dr["ANOLY"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ANOLY"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANOLY"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANOLY"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANOLY"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O ano do período letivo deve ser um valor inteiro com 4 dígitos no máximo.";
              }
            }

            if (dr["PERIODOLY"] == null || string.IsNullOrEmpty(dr["PERIODOLY"].ToString()))
            {
              return "Favor informar o semestre do período letivo.";
            }

            if (dr["PERIODOLY"] != null && !string.IsNullOrEmpty(dr["PERIODOLY"].ToString()))
            {
              if ((Convert.ToDecimal(dr["PERIODOLY"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODOLY"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["PERIODOLY"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODOLY"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O semestre do período letivo deve ser um valor inteiro com 2 dígitos no máximo.";
              }
            }

            if (dr["DATAINIPREST"] == null || string.IsNullOrEmpty(dr["DATAINIPREST"].ToString()))
            {
              return "Favor informar o início do período para prestaçăo de contas.";
            }

            if (dr["DATAINIPREST"] != null && dr["DATAINIPREST"].ToString() != "")
            {
              dr["DATAINIPREST"] = Convert.ToDateTime(dr["DATAINIPREST"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["DATAFIMPREST"] == null || string.IsNullOrEmpty(dr["DATAFIMPREST"].ToString()))
            {
              return "Favor informar o fim do prazo para prestaçăo de contas.";
            }

            if (dr["DATAFIMPREST"] != null && dr["DATAFIMPREST"].ToString() != "")
            {
              dr["DATAFIMPREST"] = Convert.ToDateTime(dr["DATAFIMPREST"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["VALORMAX_PEQDESP"] != null && !string.IsNullOrEmpty(dr["VALORMAX_PEQDESP"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALORMAX_PEQDESP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALORMAX_PEQDESP"]).ToString("0.############").Split(',')[0].Length > 9) || (Convert.ToDecimal(dr["VALORMAX_PEQDESP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALORMAX_PEQDESP"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O valor máximo para pequenas despesas deve ser um valor numérico com, no máximo, 9 dígitos na parte inteira e 2 casas decimal.";
              }
            }
      }
      return "";
    }

