          if(lower == "id_prestador") { result.Add(toLower ? "id_prestador" : column); continue; }
          if(lower == "id_periodoref") { result.Add(toLower ? "id_periodoref" : column); continue; }
          if(lower == "numero_processo") { result.Add(toLower ? "numero_processo" : column); continue; }
          if(lower == "id_situacao") { result.Add(toLower ? "id_situacao" : column); continue; }
          if(lower == "data_inicio") { result.Add(toLower ? "data_inicio" : column); continue; }
          if(lower == "data_fim") { result.Add(toLower ? "data_fim" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id", "id_prestador", "id_periodoref", "numero_processo", "id_situacao", 
                                           "data_inicio", "data_fim" }
                          : new string[] { "ID", "ID_PRESTADOR", "ID_PERIODOREF", "NUMERO_PROCESSO", "ID_SITUACAO", 
                                           "DATA_INICIO", "DATA_FIM" });
        else
          result.AddRange(toLower
                          ? new string[] { "id", "id_prestador", "id_periodoref", "numero_processo", "id_situacao", 
                                           "data_inicio", "data_fim" }
                          : new string[] { "ID", "ID_PRESTADOR", "ID_PERIODOREF", "NUMERO_PROCESSO", "ID_SITUACAO", 
                                           "DATA_INICIO", "DATA_FIM" });

      return result;
    }


