      {
            if (dr["ID_PRESTADOR"] != null && string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
              dr["ID_PRESTADOR"] = DBNull.Value;
            if (dr["ID_PERIODOREF"] != null && string.IsNullOrEmpty(dr["ID_PERIODOREF"].ToString()))
              dr["ID_PERIODOREF"] = DBNull.Value;
            if (dr["NUMERO_PROCESSO"] != null && string.IsNullOrEmpty(dr["NUMERO_PROCESSO"].ToString()))
              dr["NUMERO_PROCESSO"] = DBNull.Value;
            if (dr["ID_SITUACAO"] != null && string.IsNullOrEmpty(dr["ID_SITUACAO"].ToString()))
              dr["ID_SITUACAO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_PRESTADOR"] == null || string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
            {
              return "Favor informar o prestador de contas.";
            }

            if (dr["ID_PRESTADOR"] != null && !string.IsNullOrEmpty(dr["ID_PRESTADOR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PRESTADOR"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O prestador de contas deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["ID_PERIODOREF"] == null || string.IsNullOrEmpty(dr["ID_PERIODOREF"].ToString()))
            {
              return "Favor informar o período de referęncia.";
            }

            if (dr["ID_PERIODOREF"] != null && !string.IsNullOrEmpty(dr["ID_PERIODOREF"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_PERIODOREF"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PERIODOREF"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_PERIODOREF"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_PERIODOREF"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O período de referęncia deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["NUMERO_PROCESSO"] != null && !string.IsNullOrEmpty(dr["NUMERO_PROCESSO"].ToString()))
            {
              if (dr["NUMERO_PROCESSO"].ToString().Length > 50)
              {
                return "O número do processo deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["ID_SITUACAO"] != null && !string.IsNullOrEmpty(dr["ID_SITUACAO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_SITUACAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_SITUACAO"]).ToString("0.############").Split(',')[0].Length > 14) || (Convert.ToDecimal(dr["ID_SITUACAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_SITUACAO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "A situaçăo deve ser um valor inteiro com 14 dígitos no máximo.";
              }
            }

            if (dr["DATA_INICIO"] == null || string.IsNullOrEmpty(dr["DATA_INICIO"].ToString()))
            {
              return "Favor informar a data de início.";
            }

            if (dr["DATA_INICIO"] != null && dr["DATA_INICIO"].ToString() != "")
            {
              dr["DATA_INICIO"] = Convert.ToDateTime(dr["DATA_INICIO"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["DATA_FIM"] == null || string.IsNullOrEmpty(dr["DATA_FIM"].ToString()))
            {
              return "Favor informar a data de fim.";
            }

            if (dr["DATA_FIM"] != null && dr["DATA_FIM"].ToString() != "")
            {
              dr["DATA_FIM"] = Convert.ToDateTime(dr["DATA_FIM"]).ToString("dd/MM/yyyy HH:mm:ss");
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

