    private static TCommand CreateCommand(TConnection cn, CommandOperation operation) {
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      TCommand cm = CreateDataTableCommand(cn, operation);
      cm.CommandType = CommandType.StoredProcedure;
      cm.UpdatedRowSource = UpdateRowSource.OutputParameters;

      switch(operation) {
        case CommandOperation.Select: cm.CommandText = "zLy_pc_usuariocoord_GetCurrentValues"; break;
        case CommandOperation.Insert: cm.CommandText = "zLy_pc_usuariocoord_Cmd"; break;
        case CommandOperation.Update: cm.CommandText = "zLy_pc_usuariocoord_Cmd"; break;
        case CommandOperation.Delete: cm.CommandText = "zLy_pc_usuariocoord_Cmd"; break;
        default: throw new InvalidOperationException();
      }


      if(operation == CommandOperation.Select) {
        cm.Parameters.Add(new TParameter("idioma", OleDbType.VarChar, 0, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Default, "pt-BR"));
        cm.Parameters.Add(new TParameter("force", OleDbType.Integer, 0, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Default, 1));
      }

      cm.Parameters.Add(new TParameter("pkId_usuario", OleDbType.VarChar, 0, ParameterDirection.Input, true, 0, 0, "ID_USUARIO", DataRowVersion.Original, DBNull.Value));
      cm.Parameters.Add(new TParameter("pkId_coordenadoria", OleDbType.VarChar, 0, ParameterDirection.Input, true, 0, 0, "ID_COORDENADORIA", DataRowVersion.Original, DBNull.Value));

      cm.Parameters.Add(new TParameter("id_usuario", OleDbType.VarChar, 200, ParameterDirection.InputOutput, true, 0, 0, "ID_USUARIO", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)("__UNDEF_VARCHAR__")));
      cm.Parameters.Add(new TParameter("id_coordenadoria", OleDbType.VarChar, 200, ParameterDirection.InputOutput, true, 0, 0, "ID_COORDENADORIA", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)("__UNDEF_VARCHAR__")));
      cm.Parameters.Add(new TParameter("permissoes_coordenadoria", OleDbType.VarChar, 200, ParameterDirection.InputOutput, true, 0, 0, "PERMISSOES_COORDENADORIA", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)("__UNDEF_VARCHAR__")));
      cm.Parameters.Add(new TParameter("permissoes_escolas", OleDbType.VarChar, 200, ParameterDirection.InputOutput, true, 0, 0, "PERMISSOES_ESCOLAS", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)("__UNDEF_VARCHAR__")));

      switch(operation) {
      case CommandOperation.Insert: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Insert")); break;
      case CommandOperation.Update: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Update")); break;
      case CommandOperation.Delete: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Delete")); break;
      }
      cm.Parameters.Add(new TParameter("erro", OleDbType.VarChar, 1024, ParameterDirection.Output, true, 0, 0, string.Empty, DataRowVersion.Default, DBNull.Value));

      return cm;
    }

    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id_usuario") { result.Add(toLower ? "id_usuario" : column); continue; }
          if(lower == "id_coordenadoria") { result.Add(toLower ? "id_coordenadoria" : column); continue; }
          if(lower == "permissoes_coordenadoria") { result.Add(toLower ? "permissoes_coordenadoria" : column); continue; }
          if(lower == "permissoes_escolas") { result.Add(toLower ? "permissoes_escolas" : column); continue; }
          if(!tabPrincipal) {
            if(lower == "descricao_coordenadoria") { result.Add(toLower ? "descricao_coordenadoria" : column); continue; }
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_usuario", "id_coordenadoria", "permissoes_coordenadoria", "permissoes_escolas" }
                          : new string[] { "ID_USUARIO", "ID_COORDENADORIA", "PERMISSOES_COORDENADORIA", "PERMISSOES_ESCOLAS" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_usuario", "id_coordenadoria", "permissoes_coordenadoria", "permissoes_escolas", 
                                           "descricao_coordenadoria" }
                          : new string[] { "ID_USUARIO", "ID_COORDENADORIA", "PERMISSOES_COORDENADORIA", "PERMISSOES_ESCOLAS", 
                                           "DESCRICAO_COORDENADORIA" });

      return result;
    }


